mapper.sql:
p.enabled = TRUE

    AND p.category_id = #{categoryId}


    AND p.equipment_role = #{equipmentRole}


    AND p.daily_rate <= #{maxDailyRate}


    AND (
        p.model = #{keyword}
        OR MATCH(p.name, p.brand, p.model, p.description)
           AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)
    )

mapper.select:
SELECT p.id, p.category_id, p.equipment_role, p.name, p.brand, p.model, p.description, p.daily_rate, p.fixed_deposit, p.pricing_version FROM products p WHERE ORDER BY
CASE WHEN p.model = #{keyword} THEN 0 ELSE 1 END ASC, MATCH(p.name, p.brand, p.model, p.description) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE) DESC,
p.id ASC LIMIT #{size} OFFSET #{offset}
